class Solution:
    def isValid(self, s: str) -> bool:
        stack = deque()
        negate = {')':'(', '}':'{', ']':'['}

        for ch in s:
            if ord(ch) % 4 == 1:
                if not stack or stack.pop() != negate[ch]:
                    return False
            else:
                stack.append(ch)

        return not bool(stack)
